// 提取当前文档所有段落文本并返回摘要
var doc = Application.ActiveDocument;
var summary = "";
for (var i = 1; i <= doc.Paragraphs.Count; i++) {
    summary += doc.Paragraphs.Item(i).Range.Text + "\n";
}
return summary.substring(0, 1000) + "...";

// 统计当前文档中的表格数量
var doc = Application.ActiveDocument;
return doc.Tables.Count;

// 检查文档中的错别字
var doc = Application.ActiveDocument;
var spellErrors = 0;
for (var i = 1; i <= doc.Paragraphs.Count; i++) {
    var para = doc.Paragraphs.Item(i);
    if (para.Range.SpellingErrors.Count > 0) {
        spellErrors += para.Range.SpellingErrors.Count;
    }
}
return spellErrors;

// 提取文档中所有拼写错误的单词
var doc = Application.ActiveDocument;
var errors = [];
for (var i = 1; i <= doc.Paragraphs.Count; i++) {
    var para = doc.Paragraphs.Item(i);
    var spellErrors = para.Range.SpellingErrors;
    for (var j = 1; j <= spellErrors.Count; j++) {
        errors.push(spellErrors.Item(j).Text);
    }
}
return errors.join(', ');

// 检查文档页码是否连续
var doc = Application.ActiveDocument;
var pageCount = doc.ActiveWindow.Panes(1).Pages.Count;
var pageNumbers = [];
for (var i = 1; i <= pageCount; i++) {
    var page = doc.GoTo(What: 1, Name: i); // wdGoToPage = 1
    var pageNumber = page.Information(3); // wdActiveEndPageNumber = 3
    pageNumbers.push(pageNumber);
}
// 检查是否连续
var isContinuous = true;
for (var i = 0; i < pageNumbers.length - 1; i++) {
    if (pageNumbers[i + 1] !== pageNumbers[i] + 1) {
        isContinuous = false;
        break;
    }
}
return {
    totalPages: pageCount,
    pageNumbers: pageNumbers,
    isContinuous: isContinuous
};

