// 检查文档页码和图片编号问题
var doc = Application.ActiveDocument;
var issues = [];

// 检查页码连续性（通过Sections）
var totalPages = 0;
for (var i = 1; i <= doc.Sections.Count; i++) {
    var sec = doc.Sections.Item(i);
    var secPages = sec.Pages.Count;
    if (sec.PageSetup.SectionStart === 0) { // wdSectionContinuous
        totalPages += secPages;
    } else {
        totalPages = secPages; // 新节重新计数
    }
}
// 简单判断：如果总页数与实际不符可能存在页码问题
if (totalPages < 2) {
    issues.push("页码可能未正确设置");
}

// 检查图片编号（题注）
var captions = [];
for (var i = 1; i <= doc.Paragraphs.Count; i++) {
    var para = doc.Paragraphs.Item(i);
    if (para.Range.Style.NameLocal.indexOf("题注") !== -1 || 
        para.Range.Text.indexOf("图") === 0) {
        var text = para.Range.Text.trim();
        if (text.indexOf("图") === 0 && text.indexOf("图 ") !== 0) {
            captions.push(text);
        }
    }
}

// 检查是否有重复或跳号（简单模式：检查是否包含数字）
var hasFigureNumbers = false;
for (var i = 0; i < captions.length; i++) {
    if (/\d/.test(captions[i])) {
        hasFigureNumbers = true;
        break;
    }
}
if (!hasFigureNumbers && captions.length > 0) {
    issues.push("图片编号可能未正确添加");
}

return issues.length > 0 ? issues.join("; ") : "未发现明显页码或图片编号问题";

// 检查文档页码和图片编号问题（修正版）
var doc = Application.ActiveDocument;
var issues = [];

// 检查页码：获取文档总页数
try {
    var totalPages = doc.Range.Information(4); // wdNumberOfPagesInDocument
    if (totalPages < 2) {
        issues.push("页码可能未正确设置");
    }
} catch (e) {
    issues.push("无法读取页码信息");
}

// 检查图片题注
var figureCaptions = [];
for (var i = 1; i <= doc.Paragraphs.Count; i++) {
    var para = doc.Paragraphs.Item(i);
    var text = para.Range.Text.trim();
    if (text.indexOf("图") === 0 && text.length > 1) {
        figureCaptions.push(text);
    }
}

// 检查题注是否包含编号
var hasNumbering = false;
for (var i = 0; i < figureCaptions.length; i++) {
    if (/\d/.test(figureCaptions[i])) {
        hasNumbering = true;
        break;
    }
}
if (figureCaptions.length > 0 && !hasNumbering) {
    issues.push("图片编号可能未正确添加");
}

return issues.length > 0 ? issues.join("; ") : "未发现明显页码或图片编号问题";
